// Process Linear API response and map tickets to doc sections
const response = $input.first().json;
const cycles = response.data?.cycles?.nodes || [];

if (cycles.length === 0) {
  return [{ json: { skip: true, reason: 'No active cycle found' } }];
}

const cycle = cycles[0];
const issues = cycle.issues?.nodes || [];

if (issues.length === 0) {
  return [{ json: { skip: true, reason: 'No completed issues in active cycle' } }];
}

// Map Linear labels to doc sections
const labelToSection = {
  'api': 'docs/api-reference/endpoints.md',
  'architecture': 'docs/architecture/system-design.md',
  'frontend': 'docs/architecture/tech-stack.md',
  'backend': 'docs/architecture/system-design.md',
  'infrastructure': 'docs/architecture/tech-stack.md',
  'business': 'docs/business-requirements/user-stories.md',
  'requirements': 'docs/business-requirements/index.md',
  'deployment': 'docs/runbooks/deployment.md',
};

// Determine which doc sections need updating
const affectedSections = new Set();
affectedSections.add('docs/sprint-changelog/index.md'); // Always update changelog

const tickets = issues.map(issue => {
  const labels = (issue.labels?.nodes || []).map(l => l.name.toLowerCase());
  labels.forEach(label => {
    if (labelToSection[label]) {
      affectedSections.add(labelToSection[label]);
    }
  });

  return {
    identifier: issue.identifier,
    title: issue.title,
    description: issue.description || 'No description provided',
    labels: labels,
    assignee: issue.assignee?.name || 'Unassigned',
    completedAt: issue.completedAt
  };
});

return [{
  json: {
    skip: false,
    sprintName: cycle.name,
    sprintDateRange: `${cycle.startsAt?.split('T')[0]} to ${cycle.endsAt?.split('T')[0]}`,
    tickets: tickets,
    affectedSections: Array.from(affectedSections)
  }
}];

// Fetch current doc files from GitHub API
const data = $input.first().json;
const sections = data.affectedSections;
const repo = '{{GITHUB_REPO}}'; // e.g., 'owner/repo'
const token = '{{GITHUB_TOKEN}}';
const branch = 'main';

const currentDocs = {};

for (const filePath of sections) {
  try {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://api.github.com/repos/${repo}/contents/${filePath}?ref=${branch}`,
      headers: {
        'Authorization': `Bearer ${token}`,
        'Accept': 'application/vnd.github.v3+json',
        'User-Agent': 'DocsUpdater-n8n'
      },
      returnFullResponse: true
    });

    const body = typeof response.body === 'string' ? JSON.parse(response.body) : response.body;
    const content = Buffer.from(body.content, 'base64').toString('utf-8');
    currentDocs[filePath] = {
      content: content,
      sha: body.sha
    };
  } catch (error) {
    // File might not exist yet, skip it
    console.log(`Could not fetch ${filePath}: ${error.message}`);
  }
}

return [{
  json: {
    ...data,
    currentDocs: currentDocs
  }
}];

// Parse Claude's response and prepare files for GitHub PR
const input = $input.first().json;
const previousData = $('Fetch Current Docs').first().json;

// Extract the text content from Claude's response
const content = input.content?.[0]?.text || input.content;
let parsed;

try {
  // Handle potential markdown code fences in response
  let jsonStr = typeof content === 'string' ? content : JSON.stringify(content);
  jsonStr = jsonStr.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(jsonStr);
} catch (error) {
  return [{ json: { error: `Failed to parse Claude response: ${error.message}`, raw: content } }];
}

if (!parsed.files || Object.keys(parsed.files).length === 0) {
  return [{ json: { skip: true, summary: parsed.summary || 'No updates needed' } }];
}

// Prepare file updates with SHA for GitHub API
const fileUpdates = [];
for (const [path, newContent] of Object.entries(parsed.files)) {
  // Security check: only allow docs/ paths
  if (!path.startsWith('docs/')) {
    console.log(`Skipping non-docs path: ${path}`);
    continue;
  }

  const existingFile = previousData.currentDocs?.[path];
  fileUpdates.push({
    path: path,
    content: newContent,
    sha: existingFile?.sha || null,
    isNew: !existingFile
  });
}

return [{
  json: {
    skip: false,
    fileUpdates: fileUpdates,
    summary: parsed.summary,
    sprintName: previousData.sprintName,
    sprintDateRange: previousData.sprintDateRange
  }
}];

// Create a branch and PR on GitHub with the doc updates
const data = $input.first().json;

if (data.skip) {
  return [{ json: { result: 'skipped', reason: data.summary } }];
}

const repo = '{{GITHUB_REPO}}';
const token = '{{GITHUB_TOKEN}}';
const baseBranch = 'main';
const timestamp = new Date().toISOString().split('T')[0];
const newBranch = `docs-update/${timestamp}`;

const headers = {
  'Authorization': `Bearer ${token}`,
  'Accept': 'application/vnd.github.v3+json',
  'User-Agent': 'DocsUpdater-n8n'
};

// 1. Get the SHA of the base branch
const refResponse = await this.helpers.httpRequest({
  method: 'GET',
  url: `https://api.github.com/repos/${repo}/git/ref/heads/${baseBranch}`,
  headers
});
const baseSha = refResponse.object.sha;

// 2. Create the new branch
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `https://api.github.com/repos/${repo}/git/refs`,
    headers,
    body: {
      ref: `refs/heads/${newBranch}`,
      sha: baseSha
    }
  });
} catch (error) {
  // Branch might already exist, try with a suffix
  const suffix = Math.random().toString(36).substring(2, 6);
  const fallbackBranch = `docs-update/${timestamp}-${suffix}`;
  await this.helpers.httpRequest({
    method: 'POST',
    url: `https://api.github.com/repos/${repo}/git/refs`,
    headers,
    body: {
      ref: `refs/heads/${fallbackBranch}`,
      sha: baseSha
    }
  });
  // Use fallback branch name for the rest
  data._branch = fallbackBranch;
}

const branchName = data._branch || newBranch;

// 3. Update each file on the new branch
for (const file of data.fileUpdates) {
  const body = {
    message: `docs: update ${file.path} from sprint ${data.sprintName}`,
    content: Buffer.from(file.content, 'utf-8').toString('base64'),
    branch: branchName
  };
  if (file.sha) {
    body.sha = file.sha;
  }

  await this.helpers.httpRequest({
    method: 'PUT',
    url: `https://api.github.com/repos/${repo}/contents/${file.path}`,
    headers,
    body
  });
}

// 4. Create the Pull Request
const prResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: `https://api.github.com/repos/${repo}/pulls`,
  headers,
  body: {
    title: `docs: auto-update from sprint ${data.sprintName}`,
    body: `## Auto-Generated Documentation Update\n\n**Sprint:** ${data.sprintName} (${data.sprintDateRange})\n\n**Summary:** ${data.summary}\n\n---\n*Generated by DocsUpdater n8n workflow*`,
    head: branchName,
    base: baseBranch
  }
});

return [{
  json: {
    result: 'success',
    prUrl: prResponse.html_url,
    prNumber: prResponse.number,
    branch: branchName,
    filesUpdated: data.fileUpdates.length,
    summary: data.summary
  }
}];
